content.query:
Tailscale_Audit_CL
| where TimeGenerated {TimeRange}
| summarize EventCount = count() by bin(TimeGenerated, 1h), Action

let base = Tailscale_Devices_CL | summarize arg_max(TimeGenerated, *) by DeviceId;
union (base                                                                 | summarize V=toreal(count())                                      | extend Metric="Total devices",       Order=1),(base | where Authorized == true                                      | summarize V=toreal(count())                                      | extend Metric="Authorized",          Order=2),(base | where IsExternal == true                                      | summarize V=toreal(count())                                      | extend Metric="External (shared)",   Order=3),(base | where KeyExpiryDisabled == true                               | summarize V=toreal(count())                                      | extend Metric="Key expiry disabled", Order=4),(base | where UpdateAvailable == true                                 | summarize V=toreal(count())                                      | extend Metric="Update available",    Order=5),(base | where array_length(AdvertisedRoutes) > 0                      | summarize V=toreal(count())                                      | extend Metric="Subnet routers",      Order=6),(base | where LastSeen < ago(30d)                                     | summarize V=toreal(count())                                      | extend Metric="Stale (30+ days)",    Order=7)
| order by Order asc | project Metric, Value=V

let base = Tailscale_Users_CL | summarize arg_max(TimeGenerated, *) by UserId;
union (base                                | summarize V=toreal(count())                                | extend Metric="Users",             Order=1),(base | where Status =~ "active"   | summarize V=toreal(count())                                | extend Metric="Active",            Order=2),(base | where Status =~ "suspended" | summarize V=toreal(count())                               | extend Metric="Suspended",         Order=3),(base | where CurrentlyConnected == true | summarize V=toreal(count())                           | extend Metric="Currently connected", Order=4),(base | where DeviceCount == 0       | summarize V=toreal(count())                                | extend Metric="Zero devices",      Order=5),(base | where Role in ("owner","admin","network-admin") | summarize V=toreal(count())          | extend Metric="Elevated",          Order=6)
| order by Order asc | project Metric, Value=V

let base = Tailscale_Keys_CL | summarize arg_max(TimeGenerated, *) by KeyId | where isnull(Revoked);
union (base                                                  | summarize V=toreal(count())                  | extend Metric="Active credentials",    Order=1),(base | where KeyType =~ "auth"                       | summarize V=toreal(count())                  | extend Metric="Auth keys",             Order=2),(base | where KeyType in~ ("apiAccessToken","api_access_token","apikey") | summarize V=toreal(count()) | extend Metric="API tokens",          Order=3),(base | where KeyType in~ ("oauthClient","oauth_client")                  | summarize V=toreal(count()) | extend Metric="OAuth clients",       Order=4),(base | where isnull(Expires)                          | summarize V=toreal(count())                  | extend Metric="No expiry",             Order=5),(base | where isnotnull(Expires) and Expires < now()+7d | summarize V=toreal(count())                 | extend Metric="Expiring within 7 days", Order=6)
| order by Order asc | project Metric, Value=V

let base = Tailscale_Network_CL | where TimeGenerated {TimeRange};
union (base                                                          | summarize V=toreal(count())                                                                                                  | extend Metric="Messages",         Order=1),(base                                                          | summarize V=toreal(dcount(NodeId))                                                                                          | extend Metric="Unique nodes",     Order=2),(base | mv-expand t = VirtualTraffic                           | summarize V=toreal(sum(tolong(t.txBytes) + tolong(t.rxBytes)))                                                              | extend Metric="Bytes total (B)",  Order=3),(base | mv-expand t = ExitTraffic                              | summarize V=toreal(sum(tolong(t.txBytes) + tolong(t.rxBytes)))                                                              | extend Metric="Exit egress (B)",  Order=4),(base | mv-expand t = SubnetTraffic                            | summarize V=toreal(sum(tolong(t.txBytes) + tolong(t.rxBytes)))                                                              | extend Metric="Subnet (B)",       Order=5)
| order by Order asc | project Metric, Value=V

Tailscale_Audit_CL
| where TimeGenerated {TimeRange}
| summarize EventCount = count() by bin(TimeGenerated, 1h)
